                } else {
                    if (freshUser.email) {
                        const newUser: User = {
                            id: freshUser.uid,
                            name: freshUser.displayName || freshUser.email.split('@')[0],
                            email: freshUser.email,
                            avatar: freshUser.photoURL || `https://i.pravatar.cc/150?u=${freshUser.email}`,
                            role: 'user',
                            writeup_access: 'none',
                            status: freshUser.emailVerified ? 'pending' : 'unverified',
