      <PayloadModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingPayload(null); }} 
        onSave={handleSavePayload}
        payload={editingPayload}
        initialCategory={activePayloadCategory || 'XSS'} 
      />

      <ConfirmationModal
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDeletePayload}
