                                            >
                                                <div className="p-1 rounded-full bg-slate-200 dark:bg-slate-800 group-hover:bg-orange-100 dark:group-hover:bg-orange-900/30">
                                                    <ArrowLeftIcon className="w-4 h-4" />
                                                </div>
                                                Back to Categories
