                >
                {category}
                </button>
            ))}
            </div>
        )}
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-6 scroll-smooth">
        {mainView === 'home' && (
            <div className="max-w-5xl mx-auto h-full flex flex-col justify-center animate-fade-in">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <SelectionCard 
                        title="Open Source"
