const timeAgo = (date: Date): string => {
    const seconds = Math.floor((new Date().getTime() - date.getTime()) / 1000);
    if (seconds < 5) return "Just now";
    let interval = seconds / 31536000; if (interval > 1) return Math.floor(interval) + "y ago";
    interval = seconds / 2592000; if (interval > 1) return Math.floor(interval) + "mo ago";
    interval = seconds / 86400; if (interval > 1) return Math.floor(interval) + "d ago";
    interval = seconds / 3600; if (interval > 1) return Math.floor(interval) + "h ago";
    interval = seconds / 60; if (interval > 1) return Math.floor(interval) + "m ago";
    return Math.floor(seconds) + "s ago";
};

// New Component for modern permissions dropdown
const PermissionDropdown: React.FC<{
    currentAccess: 'none' | 'read' | 'write';
    onChange: (access: 'none' | 'read' | 'write') => void;
}> = ({ currentAccess, onChange }) => {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const accessConfig = {
        'none': { label: 'None', color: 'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300', icon: <XCircleIcon className="w-3.5 h-3.5" /> },
        'read': { label: 'Read', color: 'bg-sky-100 text-sky-700 dark:bg-sky-900/40 dark:text-sky-300', icon: <EyeIcon className="w-3.5 h-3.5" /> },
        'write': { label: 'Write', color: 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300', icon: <PencilIcon className="w-3.5 h-3.5" /> }
    };

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleSelect = (access: 'none' | 'read' | 'write') => {
        onChange(access);
        setIsOpen(false);
    };

    return (
        <div className="relative inline-block w-full" ref={dropdownRef}>
            <button 
                onClick={() => setIsOpen(!isOpen)} 
                className={`w-full flex items-center justify-center gap-2 text-xs font-bold px-3 py-2 rounded-lg transition-all border border-transparent hover:border-slate-300 dark:hover:border-slate-600 ${accessConfig[currentAccess].color}`}
            >
                {accessConfig[currentAccess].icon}
                <span>{accessConfig[currentAccess].label}</span>
            </button>
            {isOpen && (
                <div className="absolute left-0 z-20 mt-1 w-full bg-white dark:bg-slate-800 rounded-lg shadow-xl border border-slate-200 dark:border-slate-700 animate-fade-in py-1 overflow-hidden">
                    {(Object.keys(accessConfig) as Array<'none' | 'read' | 'write'>).map(access => (
                        <button
                            key={access}
                            onClick={() => handleSelect(access)}
                            className={`w-full text-left flex items-center gap-3 px-3 py-2 text-xs font-medium transition-colors ${currentAccess === access ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700'}`}
                        >
                            {React.cloneElement(accessConfig[access].icon, {className: 'w-4 h-4 opacity-70'})}
                            <span>{accessConfig[access].label}</span>
                        </button>
                    ))}
                </div>
            )}
        </div>
    );
};


const BroadcastChannel: React.FC<{ adminUser: User; allUsers: User[] }> = ({ adminUser, allUsers }) => {
    // ... (No changes to BroadcastChannel component needed for this update, keeping it as is)
    const [mode, setMode] = useState<'all' | 'single'>('all');
    const [targetUserEmail, setTargetUserEmail] = useState('');
    const [title, setTitle] = useState('');
    const [message, setMessage] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const { addNotification } = useNotificationState();
    const [suggestions, setSuggestions] = useState<User[]>([]);
    const [showSuggestions, setShowSuggestions] = useState(false);
    const broadcastRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (broadcastRef.current && !broadcastRef.current.contains(event.target as Node)) {
                setShowSuggestions(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const handleSend = async () => {
        if (!title.trim() || !message.trim()) {
            addNotification({ title: 'Error', message: 'Title and message cannot be empty.', type: 'error' });
            return;
        }

        setIsLoading(true);

        const fromPayload = {
            email: adminUser.email,
            name: adminUser.name,
            avatar: adminUser.avatar,
            role: adminUser.role,
        };

        let notificationsToSend: GlobalNotification[] = [];

        if (mode === 'all') {
            notificationsToSend = allUsers
                .filter(u => u.role !== 'admin')
                .map(u => ({
                    id: crypto.randomUUID(),
                    to: u.email,
                    from: fromPayload,
                    type: 'admin_message',
                    title,
                    message,
                }));
        } else {
            if (!targetUserEmail.trim() || !/^\S+@\S+\.\S+$/.test(targetUserEmail.trim())) {
                addNotification({ title: 'Error', message: 'Please enter a valid target user email.', type: 'error' });
                setIsLoading(false);
                return;
            }
             if (!allUsers.some(u => u.email === targetUserEmail.trim())) {
                addNotification({ title: 'Error', message: 'User with that email not found.', type: 'error' });
                setIsLoading(false);
                return;
            }
            notificationsToSend.push({
                id: crypto.randomUUID(),
                to: targetUserEmail.trim(),
                from: fromPayload,
                type: 'admin_message',
                title,
                message,
            });
        }

        if (notificationsToSend.length === 0) {
            addNotification({ title: 'Info', message: 'No users to send the message to.', type: 'info' });
            setIsLoading(false);
            return;
        }

        const success = await sendGlobalNotifications(notificationsToSend);
        setIsLoading(false);

        if (success) {
            addNotification({ title: 'Broadcast Sent', message: `Message sent to ${notificationsToSend.length} user(s).`, type: 'success' });
            setTitle('');
            setMessage('');
            setTargetUserEmail('');
        } else {
            addNotification({ title: 'Broadcast Failed', message: 'Could not send the message. Please try again.', type: 'error' });
        }
    };

    const handleTargetEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        setTargetUserEmail(value);

        if (value.trim()) {
            const filteredUsers = allUsers.filter(user =>
                user.role !== 'admin' &&
                (user.name.toLowerCase().includes(value.toLowerCase()) ||
                 user.email.toLowerCase().includes(value.toLowerCase()))
            );
            setSuggestions(filteredUsers.slice(0, 5)); // Limit suggestions to 5
            setShowSuggestions(true);
        } else {
            setShowSuggestions(false);
            setSuggestions([]);
        }
    };

    const handleSuggestionClick = (user: User) => {
        setTargetUserEmail(user.email);
        setShowSuggestions(false);
    };

    return (
        <div ref={broadcastRef} className="space-y-6 animate-fade-in" key="broadcast">
            <p className="text-slate-500 dark:text-slate-400">Send a message to all users or a specific user.</p>
            <div className="bg-white dark:bg-slate-800 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700 p-6 max-w-2xl">
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium mb-2">Recipient</label>
                        <div className="flex gap-2 rounded-lg p-1 bg-slate-200 dark:bg-slate-700 max-w-xs">
                            <button onClick={() => setMode('all')} className={`flex-1 p-2 rounded-md text-sm font-semibold transition-colors ${mode === 'all' ? 'bg-white dark:bg-slate-900 shadow' : 'hover:bg-white/50 dark:hover:bg-slate-600/50'}`}>All Users</button>
                            <button onClick={() => setMode('single')} className={`flex-1 p-2 rounded-md text-sm font-semibold transition-colors ${mode === 'single' ? 'bg-white dark:bg-slate-900 shadow' : 'hover:bg-white/50 dark:hover:bg-slate-600/50'}`}>Single User</button>
                        </div>
                    </div>
                    {mode === 'single' && (
                         <div className="animate-fade-in relative">
                            <label htmlFor="target-user" className="block text-sm font-medium mb-1">Target User Email</label>
                            <input
                                id="target-user"
                                type="email"
                                value={targetUserEmail}
                                onChange={handleTargetEmailChange}
                                onFocus={handleTargetEmailChange}
                                placeholder="e.g., user@example.com"
                                className="modern-input"
                                autoComplete="off"
                            />
                             {showSuggestions && suggestions.length > 0 && (
                                <div className="absolute z-10 w-full mt-1 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-md shadow-lg max-h-48 overflow-y-auto">
                                    <ul>
                                        {suggestions.map(user => (
                                            <li key={user.id}>
                                                <button
                                                    type="button"
                                                    onClick={() => handleSuggestionClick(user)}
                                                    className="w-full text-left px-4 py-2 hover:bg-slate-100 dark:hover:bg-slate-600 flex items-center gap-3"
                                                >
                                                    <img src={getCloudinaryUrl(user.avatar, { width: 24, height: 24, radius: 'max' })} alt={user.name} className="w-6 h-6 rounded-full" />
                                                    <div>
                                                        <div className="text-sm font-medium text-slate-800 dark:text-slate-100">{user.name}</div>
                                                        <div className="text-xs text-slate-500 dark:text-slate-400">{user.email}</div>
                                                    </div>
                                                </button>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </div>
                    )}
                    <div>
                        <label htmlFor="broadcast-title" className="block text-sm font-medium mb-1">Title</label>
                        <input id="broadcast-title" type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="e.g., Platform Maintenance" className="modern-input" />
                    </div>
                    <div>
                        <label htmlFor="broadcast-message" className="block text-sm font-medium mb-1">Message</label>
                        <textarea id="broadcast-message" value={message} onChange={e => setMessage(e.target.value)} rows={5} className="modern-textarea" placeholder="Enter your message here..."></textarea>
                    </div>
                    <div className="flex justify-end">
                        <button onClick={handleSend} disabled={isLoading} className="btn w-40 flex items-center justify-center">
                            {isLoading ? <SpinnerIcon className="w-5 h-5"/> : 'Send Broadcast'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

