                <p>Are you sure you want to clear the entire activity log? This action is permanent and cannot be undone.</p>
            </ConfirmationModal>

            <div className="flex-shrink-0 p-4 sm:p-6 md:p-8 pb-0">
                <header>
                    <h1 className="text-2xl font-bold">Admin Dashboard</h1>
                </header>
                <div className="mt-4">
                    <AdminNav 
                        currentView={view} 
                        onNavigate={(v) => onNavigateWithinApp(v)} 
