    const navItems = [
        { id: 'management', label: 'User Management', icon: <UsersIcon className="w-5 h-5"/> },
        { 
            id: 'requests', 
            label: 'Requests', 
            icon: <MailIcon className="w-5 h-5"/>, 
            count: requestsCount, 
            countColor: 'bg-indigo-100 text-indigo-800 dark:bg-indigo-900/50 dark:text-indigo-200' 
        },
        { 
