            {/* Mobile Dropdown Menu (Classic Style) */}
            {isMenuOpen && (
                <>
                    <div 
                        className="fixed inset-0 z-30 bg-black/20 backdrop-blur-[1px] md:hidden" 
                        onClick={(e) => {
