                                            <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${item.countColor}`}>
                                                {item.count}
                                            </span>
                                        )}
                                    </button>
                                );
                            })}
                        </nav>
                    </div>
                </>
            )}

            {/* Desktop Tabs (Unchanged) */}
            <nav className="hidden md:flex -mb-px space-x-6 overflow-x-auto hide-scrollbar" aria-label="Tabs">
                {navItems.map(item => (
