                        }`}
                    >
                        {item.icon}
                        {item.label}
                        {item.count !== undefined && item.count > 0 && (
                            <span className={`ml-2 inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium ${item.countColor}`}>
                                {item.count}
                            </span>
                        )}
