const parseHash = (hash: string): { appId: string | null; deepLinkInfo: string | null } => {
    // Remove # and optional leading /
    const cleanPath = hash.replace(/^#\/?/, ''); 
    if (!cleanPath) return { appId: null, deepLinkInfo: null };

    const [appId, ...rest] = cleanPath.split('/');
    const deepLinkInfo = rest.join('/');

    return { appId: appId || null, deepLinkInfo: deepLinkInfo || null };
};


const DashboardPage: React.FC<DashboardPageProps> = (props) => {
    const { 
        user, allUsers, writeups, blogPosts, setAllUsers, onLogout, 
        onSendFriendRequest, onAcceptFriendRequest, onRejectFriendRequest, onRemoveFriend, 
        onProfileUpdate,
        onSavePost, onDeletePost, onLikePost, onAddCommentToPost, onDeleteCommentFromPost,
        onRequestWriteupAccess, onApproveWriteupAccess, onRejectWriteupAccess,
        onDeleteAccount, onVerifyPassword, onEmailChange,
        isSyncingProfile
    } = props;

    const currentUser = user || GUEST_USER;
    const { themeStyle } = useTheme();
    const [windows, setWindows] = useState<WindowInstance[]>([]);
    const [isRestored, setIsRestored] = useState(false);
    const nextZIndex = useRef(10);
    const boundsRef = useRef<HTMLDivElement>(null);
    const startButtonRef = useRef<HTMLButtonElement>(null);

    const [isWorkMode, setIsWorkMode] = useState(true);

    // --- Separate Desktop/Mobile Icon Positions ---
    // We use two separate states for positions to avoid layout conflicts
    const [desktopIconPositions, setDesktopIconPositions] = useLocalStorage<Record<string, { x: number, y: number }>>(`desktop-icon-positions-${currentUser.id}`, {});
    const [mobileIconPositions, setMobileIconPositions] = useLocalStorage<Record<string, { x: number, y: number }>>(`mobile-icon-positions-${currentUser.id}`, {});

    const [activeIconId, setActiveIconId] = useState<string | null>(null);

    const [taskbarPosition, setTaskbarPosition] = useLocalStorage<TaskbarPosition>('taskbarPosition', 'bottom');
    const [desktopIconSize, setDesktopIconSize] = useLocalStorage<DesktopIconSize>('desktopIconSize', 'medium');
    const [pinnedAppIds, setPinnedAppIds] = useLocalStorage<string[]>(`pinned-apps-${currentUser.id}`, defaultPinnedApps);

    const [isStartMenuOpen, setStartMenuOpen] = useState(false);
    const [activeWindowId, setActiveWindowId] = useState<string | null>(null);

    const [unreadNotificationCount, setUnreadNotificationCount] = useState(0);
    const { notifications } = useNotificationState();

    // --- Responsive Mobile Taskbar Logic ---
    // Force 'bottom' taskbar on mobile devices to prevent layout issues
    const isMobile = useMediaQuery('(max-width: 768px)');
    const effectiveTaskbarPosition = isMobile ? 'bottom' : taskbarPosition;

    useEffect(() => {
        const unread = notifications.filter(n => !n.isRead).length;
        setUnreadNotificationCount(unread);
    }, [notifications]);

    // Handle deep links from hash
    useEffect(() => {
        const handleHashChange = () => {
            const { appId, deepLinkInfo } = parseHash(window.location.hash);

            if (appId) {
                // If it's a valid app, open it
                const app = [...baseApps, ...internalApps].find(a => a.id === appId);
                if (app) {
                    // Check if already open
                    const existingWindow = windows.find(w => w.appId === appId);
                    if (existingWindow) {
                        bringToFront(existingWindow.id);
                        if (existingWindow.isMinimized) {
                            toggleMinimize(existingWindow.id);
                        }
                        // Update props if deep link info changed
                         if (deepLinkInfo) {
                            setWindows(prev => prev.map(w => w.id === existingWindow.id ? { ...w, props: { ...w.props, deepLinkInfo }, refreshKey: w.refreshKey + 1 } : w));
                        }
                    } else {
                        openWindow(app.id, { deepLinkInfo });
                    }
                }
            }
        };

        // Run on mount
        handleHashChange();

        window.addEventListener('hashchange', handleHashChange);
        return () => window.removeEventListener('hashchange', handleHashChange);
    }, [windows]); // Depend on windows to check existing ones

    const allAppsForSearch = useMemo(() => [...baseApps, ...internalApps].filter(a => a.id !== 'start' && a.id !== 'search'), []);

    const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);

    useEffect(() => {
        const loadMessages = async () => {
            const msgs = await getChatMessages();
            setChatMessages(msgs);
        };
        loadMessages();

        const supabase = getSupabase();
        if (supabase && !isUsingMockData()) {
            const channel = supabase.channel('public:chat_messages')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'chat_messages' }, payload => {
                    if (payload.eventType === 'INSERT') {
                        // We need to fetch the author details. For simplicity in this demo, we might need a separate fetch or join
                        // Ideally the payload might not have full user details.
                        // Let's reload all for consistency or handle optimistically if we had the user in memory.
                        loadMessages(); 
                    }
                     if (payload.eventType === 'DELETE') {
                        setChatMessages(prev => prev.filter(m => m.id !== payload.old.id));
                    }
                    if (payload.eventType === 'UPDATE') {
                        loadMessages();
                    }
                })
                .subscribe();
            return () => { supabase.removeChannel(channel); };
        }
    }, []);

    const handleSendMessage = async (text: string, replyTo?: ChatMessage) => {
        const newMessage = {
            author: currentUser,
            text,
            timestamp: new Date().toISOString(),
            reply_to: replyTo ? { id: replyTo.id, authorName: replyTo.author.name, text: replyTo.text } : undefined,
            status: 'sending' as const,
        };

        // Optimistic update
        // setChatMessages(prev => [...prev, { ...newMessage, id: 'temp-' + Date.now() } as ChatMessage]);

        await addChatMessage(newMessage);
        // The realtime subscription or fetch will update the UI with the real message
    };

    const handleEditMessage = async (messageId: string, newText: string) => {
        await updateChatMessage(messageId, { text: newText, edited_timestamp: new Date().toISOString() });
    };

    const handleDeleteMessage = async (messageId: string) => {
        await deleteChatMessage(messageId);
    };

    const handleReaction = async (messageId: string, emoji: string) => {
        const message = chatMessages.find(m => m.id === messageId);
        if (!message) return;

        const currentReactions = message.reactions || {};
        const userList = currentReactions[emoji] || [];

        let newUserList;
        if (userList.includes(currentUser.email)) {
            newUserList = userList.filter(email => email !== currentUser.email);
        } else {
            newUserList = [...userList, currentUser.email];
        }

        const updatedReactions = { ...currentReactions, [emoji]: newUserList };
        if (newUserList.length === 0) {
            delete updatedReactions[emoji];
        }

        await updateChatMessage(messageId, { reactions: updatedReactions });
    };

    const handleClearChat = async () => {
        await clearChatMessages();
    };

    // --- Persistent Desktop Logic ---
    const [widgetState, setWidgetState] = useLocalStorage<WidgetState>(`widget-state-${currentUser.id}`, { x: 50, y: 50, width: 300, height: 150 });
    // Separate widget state for mobile to avoid overlap
    const [mobileWidgetState, setMobileWidgetState] = useLocalStorage<WidgetState>(`mobile-widget-state-${currentUser.id}`, { x: 20, y: 20, width: 280, height: 140 });

    useEffect(() => {
        if (!isRestored && currentUser.desktop_preferences) {
             const prefs = currentUser.desktop_preferences;
             if (prefs.iconPositions) setDesktopIconPositions(prefs.iconPositions);
             if (prefs.mobileIconPositions) setMobileIconPositions(prefs.mobileIconPositions);
             if (prefs.widgetState) setWidgetState(prefs.widgetState);
             if (prefs.mobileWidgetState) setMobileWidgetState(prefs.mobileWidgetState);
             if (prefs.pinnedAppIds) setPinnedAppIds(prefs.pinnedAppIds);
             setIsRestored(true);
        } else if (!isRestored) {
             // If no preferences, just mark as restored to stop checking
             setIsRestored(true);
        }
    }, [currentUser, isRestored, setDesktopIconPositions, setMobileIconPositions, setWidgetState, setMobileWidgetState, setPinnedAppIds]);

    // Save preferences on change (debounced could be better, but direct effect is simple)
    useEffect(() => {
        if (isRestored) {
            const prefs = {
                iconPositions: desktopIconPositions,
                mobileIconPositions: mobileIconPositions,
                widgetState: widgetState,
                mobileWidgetState: mobileWidgetState,
                pinnedAppIds: pinnedAppIds
            };

            // Only update if changed significantly? 
            // For now, we rely on the parent's `onProfileUpdate` which should be efficient enough or debounced.
             // We won't auto-save to DB on every drag to avoid heavy API calls. 
             // Ideally, save on logout or periodically.
             // For this demo, we save to local storage (handled by hook) and sync to DB on specific actions if needed.
             // Let's auto-save to DB after a delay to persist across devices.

             const timer = setTimeout(() => {
                 // Check if actually changed from user prop? Too complex to diff here efficiently.
                 // We will just update.
                 // NOTE: To prevent infinite loop if `user` prop updates from this save, we need careful handling.
                 // Actually, `onProfileUpdate` updates the user prop.
                 // Simple solution: Auto-save is tricky. Let's rely on LocalStorage for current session 
                 // and maybe save on "Save Layout" button or Logout.
                 // OR: Just save to DB on logout.
             }, 2000);
             return () => clearTimeout(timer);
        }
    }, [desktopIconPositions, mobileIconPositions, widgetState, mobileWidgetState, pinnedAppIds, isRestored]);


    const bringToFront = (id: string) => {
        setWindows((prev) => {
            const win = prev.find((w) => w.id === id);
            if (!win) return prev;
            if (win.zIndex === nextZIndex.current - 1) return prev;

            const nextWindows = prev.map((w) =>
                w.id === id ? { ...w, zIndex: nextZIndex.current, isMinimized: false } : w
            );
            nextZIndex.current += 1;
            return nextWindows;
        });
        setActiveWindowId(id);
    };

    const openWindow = (appId: string, props: Record<string, any> = {}, initialBounds?: DOMRect) => {
        setStartMenuOpen(false); // Close start menu on app launch

        // Check if app is restricted
        if (appId === 'admin' && currentUser.role !== 'admin') {
            // Shake screen or show notification
            return;
        }

        // Special handling for external/internal links that aren't windows
        // e.g. "Logout" if it were an app

        // Check if window already exists
        const existingWindow = windows.find((w) => w.appId === appId);
        if (existingWindow) {
            bringToFront(existingWindow.id);
            if (existingWindow.isMinimized) {
                toggleMinimize(existingWindow.id);
            }
            if (Object.keys(props).length > 0) {
                 setWindows(prev => prev.map(w => w.id === existingWindow.id ? { ...w, props: { ...w.props, ...props }, refreshKey: w.refreshKey + 1 } : w));
            }
            return;
        }

        const app = [...baseApps, ...internalApps].find((a) => a.id === appId);
        if (!app) return;

        const id = crypto.randomUUID();

        // Calculate initial position
        // If initialBounds (from icon click) is provided, we can animate from there (future enhancement)
        // For now, cascade windows
        const cascadeOffset = windows.length * 30;
        const defaultWidth = Math.min(800, window.innerWidth * 0.9);
        const defaultHeight = Math.min(600, window.innerHeight * 0.8);
        const x = 50 + (cascadeOffset % 200);
        const y = 50 + (cascadeOffset % 200);

        const newWindow: WindowInstance = {
            id,
            appId,
            title: app.name,
            icon: app.icon,
            x,
            y,
            width: defaultWidth,
            height: defaultHeight,
            zIndex: nextZIndex.current++,
            isMinimized: false,
            isMaximized: false,
            props,
            refreshKey: 0,
        };

        setWindows((prev) => [...prev, newWindow]);
        setActiveWindowId(id);
    };

    const closeWindow = (id: string) => {
        setWindows((prev) => {
             // Trigger closing animation first
             return prev.map(w => w.id === id ? { ...w, isClosing: true } : w);
        });

        setTimeout(() => {
            setWindows((prev) => prev.filter((w) => w.id !== id));
            if (activeWindowId === id) {
                setActiveWindowId(null);
            }

            // Clear hash if the closed window was the deep-linked one
            const { appId } = parseHash(window.location.hash);
            const closedWindow = windows.find(w => w.id === id);
            if (closedWindow && closedWindow.appId === appId) {
                 window.history.pushState("", document.title, window.location.pathname + window.location.search);
            }
        }, 250); // Wait for animation
    };

    const toggleMinimize = (id: string) => {
        setWindows((prev) =>
            prev.map((w) => (w.id === id ? { ...w, isMinimized: !w.isMinimized } : w))
        );
        if (activeWindowId === id) {
            setActiveWindowId(null);
        }
    };

    const toggleMaximize = (id: string) => {
        setWindows((prev) =>
            prev.map((w) => {
                if (w.id !== id) return w;
                if (w.isMaximized) {
                    // Restore
                    return {
                        ...w,
                        isMaximized: false,
                        x: w.preMaximizedState?.x ?? w.x,
                        y: w.preMaximizedState?.y ?? w.y,
                        width: w.preMaximizedState?.width ?? w.width,
                        height: w.preMaximizedState?.height ?? w.height,
                    };
                } else {
                    // Maximize
                    return {
                        ...w,
                        isMaximized: true,
                        preMaximizedState: { x: w.x, y: w.y, width: w.width, height: w.height },
                    };
                }
            })
        );
        bringToFront(id);
    };

    const refreshWindow = (id: string) => {
        setWindows(prev => prev.map(w => w.id === id ? { ...w, refreshKey: w.refreshKey + 1 } : w));
    }

    const updateWindowBounds = (id: string, bounds: { x: number; y: number; width: number; height: number }) => {
        setWindows((prev) => prev.map((w) => (w.id === id ? { ...w, ...bounds } : w)));
    };

    const handleLogoutWithSave = () => {
         // Save preferences before logout
         onProfileUpdate(currentUser.email, {
             desktop_preferences: {
                 iconPositions: desktopIconPositions,
                 mobileIconPositions: mobileIconPositions,
                 widgetState: widgetState,
                 mobileWidgetState: mobileWidgetState,
                 pinnedAppIds: pinnedAppIds
             }
         }, true);
         onLogout();
    };

    const handleSearch = (query: string) => {
        openWindow('search', { query });
    };

    const handleIconPositionChange = (appId: string, pos: { x: number; y: number }) => {
        const setPositions = isMobile ? setMobileIconPositions : setDesktopIconPositions;
        setPositions(prev => ({ ...prev, [appId]: pos }));
    };

    const renderAppContent = (appId: string, props: any = {}) => {
        const commonProps = { 
            user: currentUser,
            onOpenApp: (id: string, p: any, e: any) => {
                 if (e) e.stopPropagation(); // Prevent bubbling if passed
                 openWindow(id, p);
            },
            onNavigateWithinApp: (path: string) => {
                 // Update URL hash for deep linking
                 window.location.hash = `#${path}`;
            }
        };

        switch (appId) {
            case 'home': return <HomePage {...commonProps} writeups={writeups} isPending={currentUser.status === 'pending'} />;
            case 'mywork': return <MyWorkPage {...commonProps} allUsers={allUsers} writeups={writeups} blogPosts={blogPosts} profileUserEmail={props.profileUserEmail} />;
            case 'writeup': return <WriteupPage {...commonProps} posts={writeups} onSavePost={(p) => onSavePost(p, 'writeup')} onDeletePost={onDeletePost} onLikePost={onLikePost} onAddCommentToPost={onAddCommentToPost} onDeleteCommentFromPost={onDeleteCommentFromPost} onRequestAccess={onRequestWriteupAccess} deepLinkInfo={props.deepLinkInfo} />;
            case 'blog': return <BlogPage {...commonProps} posts={blogPosts} onSavePost={(p) => onSavePost(p, 'blog')} onDeletePost={onDeletePost} onLikePost={onLikePost} onAddCommentToPost={onAddCommentToPost} onDeleteCommentFromPost={onDeleteCommentFromPost} deepLinkInfo={props.deepLinkInfo} />;
            case 'chat': return <ChatPage {...commonProps} allUsers={allUsers} messages={chatMessages} onSendMessage={handleSendMessage} onEditMessage={handleEditMessage} onDeleteMessage={handleDeleteMessage} onReaction={handleReaction} onClearChat={handleClearChat} />;
            case 'notes': return <NotesPage {...commonProps} />;
            case 'todolist': return <TodolistPage {...commonProps} />;
            case 'settings': return <SettingsPage {...commonProps} allUsers={allUsers} setAllUsers={setAllUsers} taskbarPosition={taskbarPosition} setTaskbarPosition={setTaskbarPosition} desktopIconSize={desktopIconSize} setDesktopIconSize={setDesktopIconSize} onAcceptFriendRequest={onAcceptFriendRequest} onRejectFriendRequest={onRejectFriendRequest} onRemoveFriend={onRemoveFriend} onSendFriendRequest={onSendFriendRequest} onLogout={handleLogoutWithSave} onProfileUpdate={(data, silent) => onProfileUpdate(currentUser.email, data, silent)} onDeleteAccount={onDeleteAccount} onVerifyPassword={onVerifyPassword} onEmailChange={onEmailChange} deepLinkInfo={props.deepLinkInfo} />;
            case 'search': return <SearchPage {...commonProps} query={props.query || props.deepLinkInfo} allApps={[...baseApps, ...internalApps]} allPosts={[...writeups, ...blogPosts]} onClose={() => closeWindow(activeWindowId!)} />;
            case 'admin': return <AdminDashboardPage {...commonProps} allUsers={allUsers} setAllUsers={setAllUsers} onApproveWriteupAccess={onApproveWriteupAccess} onRejectWriteupAccess={onRejectWriteupAccess} deepLinkInfo={props.deepLinkInfo} liveUsers={[{ name: currentUser.name, email: currentUser.email, avatar: currentUser.avatar }]} />; // Mock live user
            case 'notifications': return <NotificationCenterPage {...commonProps} />;
            case 'resources': return <ResourcesPage {...commonProps} />;
            case 'kali': return <KaliPage />;
            case 'docs': return <DocPage />;
            case 'copyright': return <CopyrightPage onClose={() => closeWindow('copyright')} />;
            default: return <div className="p-4">App not found</div>;
        }
    };

    // Calculate Grid Layout for Icons if no position saved
    const getIconPosition = (index: number) => {
        const iconSize = getIconSizePixels(desktopIconSize);
        const gap = 16;
        const gridHeight = window.innerHeight - 60; // Approximate available height minus taskbar
        const itemsPerCol = Math.floor(gridHeight / (iconSize + gap));

        const col = Math.floor(index / itemsPerCol);
        const row = index % itemsPerCol;

        return {
            x: 20 + col * (iconSize + gap + 20),
            y: 20 + row * (iconSize + gap)
        };
    };

    const currentIconPositions = isMobile ? mobileIconPositions : desktopIconPositions;
    const currentWidgetState = isMobile ? mobileWidgetState : widgetState;
    const handleWidgetChange = isMobile ? setMobileWidgetState : setWidgetState;

    // Desktop/Windows Area Padding calculation based on Taskbar
    const desktopStyle = useMemo(() => {
        const tbSize = 56; // Standard taskbar height
        const sideTbWidth = 64; // Side taskbar width

        // Use effectiveTaskbarPosition here
        switch (effectiveTaskbarPosition) {
            case 'bottom': return { paddingBottom: `${tbSize}px` };
            case 'top': return { paddingTop: `${tbSize}px` };
            case 'left': return { paddingLeft: `${sideTbWidth}px` };
            case 'right': return { paddingRight: `${sideTbWidth}px` };
            default: return { paddingBottom: `${tbSize}px` };
        }
    }, [effectiveTaskbarPosition]);

    if (!isWorkMode) {
        return <SleepScreen onWake={() => setIsWorkMode(true)} />;
    }

    return (
        <div className="h-full w-full relative overflow-hidden bg-cover bg-center transition-all duration-500" ref={boundsRef}>
             {/* Start Menu Overlay */}
             {isStartMenuOpen && (
                <div 
                    className="absolute z-[10000]"
                    style={{
                        bottom: effectiveTaskbarPosition === 'bottom' ? '60px' : 'auto',
                        top: effectiveTaskbarPosition === 'top' ? '60px' : (effectiveTaskbarPosition === 'bottom' ? 'auto' : '0'),
                        left: effectiveTaskbarPosition === 'left' ? '68px' : (effectiveTaskbarPosition === 'right' ? 'auto' : '0'),
                        right: effectiveTaskbarPosition === 'right' ? '68px' : 'auto',
                        height: (effectiveTaskbarPosition === 'left' || effectiveTaskbarPosition === 'right') ? '100%' : 'auto',
                        width: (effectiveTaskbarPosition === 'left' || effectiveTaskbarPosition === 'right') ? '320px' : (isMobile ? '100%' : '600px'),
                        maxHeight: (effectiveTaskbarPosition === 'top' || effectiveTaskbarPosition === 'bottom') ? '80vh' : '100%',
                    }}
                >
                    <div 
                        className="fixed inset-0" 
                        onClick={() => setStartMenuOpen(false)}
                    />
                    <div className={`relative h-full w-full rounded-xl overflow-hidden shadow-2xl animate-scale-in origin-${effectiveTaskbarPosition === 'bottom' ? 'bottom-left' : effectiveTaskbarPosition === 'top' ? 'top-left' : effectiveTaskbarPosition === 'left' ? 'left-top' : 'right-top'}`}>
                         <StartMenuContent 
                            onSearch={handleSearch}
                            pinnedAppIds={pinnedAppIds}
                            setPinnedAppIds={setPinnedAppIds}
                            allApps={[...baseApps, ...internalApps].filter(a => a.id !== 'start')}
                            onOpenApp={(id, e) => openWindow(id, {}, e as any)}
                            user={currentUser}
                            onLogout={handleLogoutWithSave}
                            onClose={() => setStartMenuOpen(false)}
                            searchablePosts={[...writeups, ...blogPosts]}
                            addNotification={props.onProfileUpdate ? () => {} : () => {}} // Placeholder if not needed inside
                            isWorkMode={isWorkMode}
                            onToggleWorkMode={() => setIsWorkMode(false)}
                         />
                    </div>
                </div>
            )}

            {/* Desktop Area */}
            <div className="absolute inset-0 pointer-events-none" style={desktopStyle}>
                 <div className="relative w-full h-full pointer-events-auto">
                    {/* Widgets */}
                     <DesktopWidgets 
                        state={currentWidgetState} 
                        onStateChange={handleWidgetChange} 
                        boundsRef={boundsRef}
                    />

                    {/* Desktop Icons */}
                    {baseApps.map((app, index) => {
                        const savedPos = currentIconPositions[app.id];
                        const pos = savedPos || getIconPosition(index);

                        return (
                            <DesktopIcon
                                key={app.id}
                                app={app}
                                x={pos.x}
                                y={pos.y}
                                onOpen={(id) => openWindow(id)}
                                onPositionChange={handleIconPositionChange}
                                boundsRef={boundsRef}
                                isSelected={activeIconId === app.id}
                                onSelect={setActiveIconId}
                                size={desktopIconSize}
                            />
                        );
                    })}

                    {/* Windows */}
                    {windows.map((win) => {
                         const app = [...baseApps, ...internalApps].find(a => a.id === win.appId);
                         const accentColor = app ? app.accentColor : '#64748b'; // default slate

                         return !win.isMinimized && (
                            <Window
                                key={win.id}
                                {...win}
                                icon={win.icon}
                                isActive={activeWindowId === win.id}
                                accentColor={accentColor}
                                onClose={closeWindow}
                                onMinimize={toggleMinimize}
                                onMaximize={toggleMaximize}
                                onFocus={bringToFront}
                                onBoundsChange={updateWindowBounds}
                                onRefresh={refreshWindow}
                                boundsRef={boundsRef}
                            >
                                <React.Suspense fallback={<div className="h-full flex items-center justify-center"><SpinnerIcon className="w-8 h-8 animate-spin text-indigo-500"/></div>}>
                                    {renderAppContent(win.appId, win.props)}
                                </React.Suspense>
                            </Window>
                        );
                    })}
                 </div>
            </div>

            <Taskbar
                position={effectiveTaskbarPosition}
                apps={pinnedAppIds.map(id => [...baseApps, ...internalApps].find(a => a.id === id)).filter(Boolean) as AppDefinition[]}
                openWindows={windows}
                activeWindowId={activeWindowId}
                onAppClick={(id) => {
                    if (id === 'start') {
                        setStartMenuOpen(!isStartMenuOpen);
                    } else if (id === 'search') {
                         openWindow('search');
                    } else if (id === 'settings') {
                         openWindow('settings');
                    } else {
                        const win = windows.find(w => w.appId === id);
                        if (win) {
                            if (win.isMinimized) {
                                toggleMinimize(win.id);
                                bringToFront(win.id);
                            } else if (activeWindowId === win.id) {
                                toggleMinimize(win.id);
                            } else {
                                bringToFront(win.id);
                            }
                        } else {
                            openWindow(id);
                        }
                    }
                }}
                onStartClick={() => setStartMenuOpen(!isStartMenuOpen)}
                isStartMenuOpen={isStartMenuOpen}
                startButtonRef={startButtonRef}
                user={currentUser}
                onLogout={handleLogoutWithSave}
                onOpenSettings={() => openWindow('settings')}
                isAnyWindowMaximized={windows.some(w => w.isMaximized && !w.isMinimized)}
                allAppsForSearch={allAppsForSearch}
                searchablePosts={[...writeups, ...blogPosts]}
                onSearch={handleSearch}
                unreadNotificationCount={unreadNotificationCount}
                onOpenNotifications={() => openWindow('notifications')}
            />
        </div>
    );
};

