  const [isInitialAuthLoading, setIsInitialAuthLoading] = useState(true);
  const [isAuthExiting, setAuthExiting] = useState(false);
  const [showWelcomeAnimation, setShowWelcomeAnimation] = useState(false);
  const [userForWelcome, setUserForWelcome] = useState<User | null>(null);
  const [showDeletionAnimation, setShowDeletionAnimation] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState<string | null>(null);
  const [isResending, setIsResending] = useState(false);
  const [resendCooldown, setResendCooldown] = useState(0);
  const [verificationCheckCount, setVerificationCheckCount] = useState(0);
  const [emailFor2FA, setEmailFor2FA] = useState<string | null>(null);
  const [isChecking2FA, setIsChecking2FA] = useState(false);
  const [isVerifying2FA, setIsVerifying2FA] = useState(false);
  const [twoFAError, setTwoFAError] = useState<string | null>(null);
  const [twoFAAttemptFailed, setTwoFAAttemptFailed] = useState(0);
  const is2FASignOutRef = useRef(false);
  const [isSyncingProfile, setIsSyncingProfile] = useState(false);
  const isSigningUpRef = useRef(false);

  // NEW: Login orchestration guard to prevent listener races
  const isPerformingLoginRef = useRef(false);

  const authBodyRef = useRef<HTMLDivElement>(null);

  // Ref to track the current user to avoid re-triggering login flow on profile updates.
  const appUserRef = useRef(appUser);
  appUserRef.current = appUser;

  // --- Centralized State Management ---
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [writeups, setWriteups] = useState<Post[]>([]);
  const [blogPosts, setBlogPosts] = useState<Post[]>([]);
  const [isDbLoading, setDbLoading] = useState(true);

  // --- Notification State Management ---
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [toasts, setToasts] = useState<Notification[]>([]);
  const [queuedNotifications, setQueuedNotifications] = useState<Notification[]>([]);

  // Ref to provide a stable reference to notifications in effects that shouldn't re-run when notifications change.
  const notificationsRef = useRef(notifications);
  notificationsRef.current = notifications;

  // Use a ref to queue notifications during the welcome animation, preventing race conditions.
  const isWelcomeAnimationRunning = useRef(false);

  // Ref to provide stable access to allUsers in callbacks without re-triggering effects.
  const allUsersRef = useRef(allUsers);
  allUsersRef.current = allUsers;

  // Sync wallpaper from user profile to ThemeContext
  useEffect(() => {
    if (appUser?.wallpaper && appUser.wallpaper !== selectedBackground) {
        setSelectedBackground(appUser.wallpaper);
    }
  }, [appUser?.wallpaper, setSelectedBackground]); 

  // 404 Route Checker
  useEffect(() => {
    const checkRoute = () => {
        if (appUserRef.current) return; 

        const hash = window.location.hash;
        const cleanHash = hash.replace(/^#\/?/, ''); 
        const validRoots = ['', '#', '#/'];

        const validProtectedApps = ['home', 'writeup', 'blog', 'chat', 'notes', 'todolist', 'settings', 'search', 'start', 'admin', 'notifications', 'mywork', 'resources', 'kali', 'docs'];

        const currentApp = cleanHash.split('/')[0];

        const isAuthRoute = cleanHash.startsWith('auth');
        const isRootRoute = validRoots.includes(hash) || cleanHash === '';
        const isProtectedAppRoute = validProtectedApps.includes(currentApp);

        if (!isAuthRoute && !isRootRoute && !isProtectedAppRoute) {
            setIs404(true);
            setShowLanding(false);
            setAuthPage(null);
        } else if (isProtectedAppRoute) {
            setIs404(false);
            setShowLanding(true);
            setAuthPage(null);
            if (window.location.hash !== '#/') {
                window.location.hash = '#/';
            }
        } else {
            setIs404(false);
        }
    };

    checkRoute();
    window.addEventListener('hashchange', checkRoute);
    return () => window.removeEventListener('hashchange', checkRoute);
  }, []);

  // Effect to prevent body scroll on mobile when dashboard is active
  useEffect(() => {
    const rootEl = document.documentElement; 
    if (authPage === null && appUser) {
      rootEl.classList.add('dashboard-active');
      document.body.classList.add('dashboard-active');
    } else {
      rootEl.classList.remove('dashboard-active');
      document.body.classList.remove('dashboard-active');
    }

    return () => {
      rootEl.classList.remove('dashboard-active');
      document.body.classList.remove('dashboard-active');
    };
  }, [authPage, appUser]);

  const refreshPosts = useCallback(async () => {
    try {
        const [w, b] = await Promise.all([getPosts('writeup'), getPosts('blog')]);
        setWriteups(w);
        setBlogPosts(b);
    } catch (e) {
        console.error("Failed to refresh posts:", e);
    }
  }, []);

  // Force refresh when user changes to ensure visibility of data
  useEffect(() => {
      if (appUser) {
          refreshPosts();
      }
  }, [appUser, refreshPosts]);

  // Effect to sync post authors with updated user data
  useEffect(() => {
    const syncAuthors = (setPosts: React.Dispatch<React.SetStateAction<Post[]>>) => {
      setPosts(prev => {
        let changed = false;
        const next = prev.map(post => {
          const user = allUsers.find(u => u.id === post.author.id);
          // Check if we have better user data than what's in the post (or if post has placeholder)
          if (user && (post.author.name === 'Loading...' || JSON.stringify(user) !== JSON.stringify(post.author))) {
            changed = true;
            return { ...post, author: user };
          }
          return post;
        });
        return changed ? next : prev;
      });
    };

    if (allUsers.length > 0) {
        syncAuthors(setWriteups);
        syncAuthors(setBlogPosts);
    }
  }, [allUsers]);

  const addNotification = useCallback((notification: Omit<Notification, 'id' | 'timestamp' | 'isRead' | 'userId'>) => {
    const newNotificationStub: Notification = {
        id: `${Date.now()}-${Math.random()}`,
        timestamp: new Date().toISOString(),
        isRead: false,
        ...notification,
    };

    const shouldShowToast = notification.showToast === undefined ? true : notification.showToast;

    if (shouldShowToast) {
        if (isWelcomeAnimationRunning.current) {
            setQueuedNotifications(prev => [...prev, newNotificationStub]);
        } else {
            setToasts(prev => [...prev, newNotificationStub]);
        }
    }

    if (notification.persist) {
        if (!appUserRef.current) return;
        const newNotificationForDb = {
            userId: appUserRef.current.id,
            title: notification.title,
            message: notification.message,
            type: notification.type || 'info',
            sourceType: notification.sourceType,
            fromUser: notification.fromUser,
            actions: notification.actions,
            persist: true,
            targetId: notification.targetId,
            targetType: notification.targetType,
        };

        addNotificationToDb(newNotificationForDb)
            .catch(error => {
                console.error("Failed to save notification to database:", error);
                const errorToast: Omit<Notification, 'id' | 'timestamp' | 'isRead'> = {
                    title: "Sync Error",
                    message: "Could not save notification to your account.",
                    type: 'error',
                    persist: false, 
                };
                setToasts(prev => [...prev, { ...errorToast, id: crypto.randomUUID(), timestamp: new Date().toISOString(), isRead: false }]);
            });
    }
  }, []);

  useEffect(() => {
    const handleOffline = () => {
        localStorage.setItem('offlineTimestamp', Date.now().toString());
        addNotification({
            title: "You're Offline",
            message: "Your connection was lost. Some features may be unavailable.",
            type: 'warning',
            duration: 7000,
        });
    };

    const handleOnline = () => {
        const offlineStart = localStorage.getItem('offlineTimestamp');
        if (offlineStart) {
            const offlineDuration = Date.now() - parseInt(offlineStart, 10);
            localStorage.removeItem('offlineTimestamp');

            const OFFLINE_THRESHOLD = 30 * 1000; 

            if (offlineDuration > OFFLINE_THRESHOLD) {
                addNotification({
                    title: "Welcome Back Online!",
                    message: "For a better experience next time, consider installing our app to use it offline.",
                    type: 'info',
                    duration: 10000,
                    persist: true,
                });
            } else {
                 addNotification({
                    title: "Connection Restored",
                    message: "You are back online.",
                    type: 'success',
                    duration: 5000,
                });
            }
        }
    };

    window.addEventListener('offline', handleOffline);
    window.addEventListener('online', handleOnline);

    return () => {
        window.removeEventListener('offline', handleOffline);
        window.removeEventListener('online', handleOnline);
    };
}, [addNotification]);

  const logActivity = useCallback((action: string, target?: string) => {
    if (appUserRef.current) {
        addActivityLog(appUserRef.current.id, action, target);
    }
  }, []);

  useEffect(() => {
    const fetchInitialData = async () => {
      try {
        const users = await getAllUsers();
        setAllUsers(users.length > 0 ? users : MOCK_USERS);
      } catch (e) {
      }

      // Initial post fetch
      await refreshPosts();

      if (isUsingMockData()) {
          addNotification({
              title: "Offline Mode Active",
              message: "Could not connect to database. Using sample data. App is functional for demonstration.",
              type: 'warning',
              duration: 10000,
          });
      }

      setDbLoading(false);
    };

    fetchInitialData();

    const supabase = getSupabase();
    if (supabase) {
        const postsChannel = supabase.channel('public:posts')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, payload => {
                // DELETE Handler: Ensure we handle deletion even if `type` is missing in payload.old
                if (payload.eventType === 'DELETE') {
                    const idToDelete = payload.old.id;
                    setWriteups(current => current.filter(p => p.id !== idToDelete));
                    setBlogPosts(current => current.filter(p => p.id !== idToDelete));
                    return;
                }

                // INSERT/UPDATE Handlers
                const postType = (payload.new as Post)?.type;
                const targetStateUpdater = postType === 'writeup' ? setWriteups : postType === 'blog' ? setBlogPosts : null;

                if (!targetStateUpdater) return;

                if (payload.eventType === 'INSERT') {
                    const sanitizedNewPost = sanitizePostPayload(payload.new);
                    // Try to resolve author from local cache if missing or incomplete
                    if (sanitizedNewPost.author.name === 'Deleted User' || !sanitizedNewPost.author.name) {
                         const foundAuthor = allUsersRef.current.find(u => u.id === (payload.new as any).author_id);
                         if (foundAuthor) sanitizedNewPost.author = foundAuthor;
                    }
                    targetStateUpdater(current => {
                        // Avoid duplicates
                        if (current.some(p => p.id === sanitizedNewPost.id)) return current;
                        return [sanitizedNewPost, ...current];
                    });
                }
                if (payload.eventType === 'UPDATE') {
                    targetStateUpdater(current => current.map(p => {
                        if (p.id === payload.new.id) {
                            const rawNew = payload.new as any;
                            const sanitizedNew = sanitizePostPayload(rawNew);

                            const finalComments = (rawNew.comments === undefined || rawNew.comments === null)
                                ? p.comments
                                : sanitizedNew.comments;

                            const finalContent = (rawNew.content === undefined || rawNew.content === null)
                                ? p.content
                                : sanitizedNew.content;

                            const finalAuthor = (sanitizedNew.author.name === 'Deleted User' && p.author.name !== 'Deleted User') 
                                ? p.author 
                                : sanitizedNew.author;

                            return { 
                                ...p, 
                                ...sanitizedNew, 
                                author: finalAuthor,
                                comments: finalComments,
                                content: finalContent
                            };
                        }
                        return p;
                    }));
                }
            })
            .subscribe();

        const usersChannel = supabase.channel('public:users')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'users' },
            (payload) => {
                if (payload.eventType === 'INSERT') {
                    const newUser = sanitizeUserPayload(payload.new);
                    setAllUsers(prev => [...prev.filter(u => u.id !== newUser.id), newUser]);
                }
                if (payload.eventType === 'UPDATE') {
                    setAllUsers(prevUsers => {
                        const updatedUser = sanitizeUserPayload(payload.new);
                        const userToUpdate = prevUsers.find(u => u.id === updatedUser.id);

                        if (!userToUpdate) {
                            return [...prevUsers, updatedUser];
                        }

                        // Create copies for comparison, ignoring the property that is expected to change.
                        const { desktop_preferences: oldPrefs, ...oldUserRest } = userToUpdate;
                        const { desktop_preferences: newPrefs, ...newUserRest } = updatedUser;

                        // Compare the rest of the user object. A shallow compare is not enough
                        // as nested properties like arrays (e.g., friends) would be missed.
                        if (JSON.stringify(oldUserRest) === JSON.stringify(newUserRest)) {
                            // Only desktop_preferences changed. Return the original array reference
                            // to prevent re-rendering the entire Dashboard.
                            return prevUsers;
                        } else {
                            // A meaningful property (e.g., name, role, friends) has changed.
                            // Return a new array to trigger necessary UI updates.
                            return prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u));
                        }
                    });

                    if (appUserRef.current?.id === payload.new.id) {
                        const updatedUser = sanitizeUserPayload(payload.new);
                        const oldUser = appUserRef.current;
                        const { desktop_preferences: oldPrefs, ...oldUserRest } = oldUser;
                        const { desktop_preferences: newPrefs, ...newUserRest } = updatedUser;

                        if (JSON.stringify(oldUserRest) !== JSON.stringify(newUserRest)) {
                            setAppUser(updatedUser);
                        }
                    }
                }
                if (payload.eventType === 'DELETE') {
                    const oldUserId = (payload.old as any).id;
                    setAllUsers(prev => prev.filter(u => u.id !== oldUserId));
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(postsChannel);
            supabase.removeChannel(usersChannel);
        };
    }
  }, [addNotification, refreshPosts]);

  // Realtime listener for persistent notifications
  useEffect(() => {
    const supabase = getSupabase();
    if (!supabase || !appUser) return;

    const notificationsChannel = supabase.channel(`public:notifications-for-${appUser.id}`)
        .on('postgres_changes', { 
            event: 'INSERT', 
            schema: 'public', 
            table: 'notifications',
            filter: `user_id=eq.${appUser.id}`
        }, (payload) => {
            const newNotification = mapDbNotificationToApp(payload.new);
            setNotifications(prev => {
                if (prev.some(n => n.id === newNotification.id)) {
                    return prev;
                }
                return [newNotification, ...prev].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            });
        })
        .on('postgres_changes', { 
            event: 'UPDATE', 
            schema: 'public', 
            table: 'notifications',
            filter: `user_id=eq.${appUser.id}`
        }, (payload) => {
             if ((payload.new as any).is_deleted) { 
                 setNotifications(prev => prev.filter(n => n.id !== payload.new.id));
             } else {
                 const updatedNotification = mapDbNotificationToApp(payload.new);
                 setNotifications(prev => prev.map(n => n.id === updatedNotification.id ? updatedNotification : n));
             }
        })
        .subscribe();

    return () => {
        supabase.removeChannel(notificationsChannel);
    };
}, [appUser]);


