                if (!freshUser.emailVerified) {
                    setVerificationEmail(freshUser.email);
                    setAppUser(null);
                    setNotifications([]);
                    setToasts([]);
                    setShowLanding(false); 
                    setIs404(false);
                    setAuthPage('auth');
                    setAuthInitialMode('verify');
                    setAuthLoading(false);
                    setIsInitialAuthLoading(false);
                    return;
