                        setAuthPage(null);
                    }
                }

                setAuthInitialMode('signin');
                setAuthExiting(false);
                setAuthLoading(false);
            }
            setIsInitialAuthLoading(false);
        });
    };

    setupAuthListener();

    return () => {
        if (unsubscribe) {
            unsubscribe();
        }
    };
