import { authenticator } from 'otplib';
import type { Handler, HandlerEvent } from "@netlify/functions";

const sendResponse = (statusCode: number, body: object) => ({
  statusCode,
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify(body),
});

export const handler: Handler = async (event: HandlerEvent) => {
  if (event.httpMethod !== 'POST') return sendResponse(405, { message: 'Method Not Allowed' });

  try {
    const { email } = JSON.parse(event.body || '{}');
    if (!email) return sendResponse(400, { message: 'Email is required' });

    // Generate a secure secret
    const secret = authenticator.generateSecret();

    // Generate the otpauth URL for QR codes
    // Format: otpauth://totp/Label:email?secret=...&issuer=Label
    const otpauth = authenticator.keyuri(email, 'HtWtH', secret);

    return sendResponse(200, { secret, otpauth });
  } catch (error: any) {
    console.error('Generate 2FA Error:', error);
    return sendResponse(500, { message: 'Internal Server Error' });
  }
};

import { createClient } from '@supabase/supabase-js';
import { authenticator } from 'otplib';
import type { Handler, HandlerEvent } from "@netlify/functions";

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);

const sendResponse = (statusCode: number, body: object) => ({
  statusCode,
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify(body),
});

export const handler: Handler = async (event: HandlerEvent) => {
  if (event.httpMethod !== 'POST') return sendResponse(405, { message: 'Method Not Allowed' });

  try {
    const { email, secret, code } = JSON.parse(event.body || '{}');
    if (!email || !secret || !code) return sendResponse(400, { message: 'Missing required fields' });

    // Verify the token
    const isValid = authenticator.check(code, secret);

    if (!isValid) {
        return sendResponse(400, { success: false, message: 'Invalid verification code.' });
    }

    // Save secret and enable 2FA
    // Also generate backup codes if not present
    const backupCodes = Array.from({ length: 6 }, () => 
        Math.floor(100000 + Math.random() * 900000).toString()
    );

    const { error } = await supabase
        .from('users')
        .update({ 
            totp_secret: secret, 
            is_2fa_enabled: true,
            backup_codes: backupCodes 
        })
        .eq('email', email);

    if (error) throw error;

    return sendResponse(200, { success: true, backupCodes });
  } catch (error: any) {
    console.error('Finalize 2FA Error:', error);
    return sendResponse(500, { message: 'Internal Server Error' });
  }
};

import { createClient } from '@supabase/supabase-js';
import { authenticator } from 'otplib';
import type { Handler, HandlerEvent } from "@netlify/functions";

const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);

const sendResponse = (statusCode: number, body: object) => ({
  statusCode,
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify(body),
});

export const handler: Handler = async (event: HandlerEvent) => {
  if (event.httpMethod !== 'POST') return sendResponse(405, { message: 'Method Not Allowed' });

  try {
    const { email, code } = JSON.parse(event.body || '{}');
    if (!email || !code) return sendResponse(400, { message: 'Missing fields' });

    // Fetch user secrets
    const { data: user, error } = await supabase
        .from('users')
        .select('id, totp_secret, backup_codes')
        .eq('email', email)
        .single();

    if (error || !user) return sendResponse(404, { message: 'User not found' });

    let isValid = false;
    let usedBackupCode = false;

    // 1. Check TOTP
    if (user.totp_secret) {
        try {
            isValid = authenticator.check(code, user.totp_secret);
        } catch (e) {
            console.error("TOTP Check Error", e);
        }
    }

    // 2. Check Backup Codes
    if (!isValid && user.backup_codes && Array.isArray(user.backup_codes)) {
        if (user.backup_codes.includes(code)) {
            isValid = true;
            usedBackupCode = true;
        }
    }

    if (isValid) {
        // If backup code used, remove it
        if (usedBackupCode) {
            const newCodes = user.backup_codes!.filter((c: string) => c !== code);
            await supabase.from('users').update({ backup_codes: newCodes }).eq('id', user.id);
        }
        return sendResponse(200, { success: true });
    } else {
        return sendResponse(400, { success: false, message: 'Invalid code.' });
    }

  } catch (error: any) {
    console.error('Verify 2FA Error:', error);
    return sendResponse(500, { message: 'Internal Server Error' });
  }
};

