                if (profileFromDb) {
                     // --- 2FA ENFORCEMENT ---
                     if (profileFromDb.is_2fa_enabled && !is2FASignOutRef.current) {
                        // Check if session is already verified for 2FA
                        const isVerifiedSession = sessionStorage.getItem(`2fa_verified_${freshUser.uid}`);

