                        }
                        default: 
                            addNotification({ title: 'Access Denied', message: 'Your account is not active.', type: 'error' });
                            signOut(auth);
                            break;
                    }
                } else {
                    if (freshUser.email) {
                        const newUser: User = {
                            id: freshUser.uid,
                            name: freshUser.displayName || freshUser.email.split('@')[0],
                            email: freshUser.email,
