                        setIs404(false);
                        setAuthPage(null);
                    }
                }

                setAuthInitialMode('signin');
                setAuthExiting(false);
                setAuthLoading(false);
            }
            setIsInitialAuthLoading(false);
        });
    };

    setupAuthListener();

    return () => {
        if (unsubscribe) {
            unsubscribe();
        }
    };
}, [isDbLoading, addNotification, isChecking2FA, performLogin, refreshPosts]);


