// New 2FA Setup Modal
const TwoFASetupModal: React.FC<{
    isOpen: boolean;
    onClose: () => void;
    email: string;
    onComplete: (backupCodes: string[]) => void;
}> = ({ isOpen, onClose, email, onComplete }) => {
    const [step, setStep] = useState<1 | 2>(1);
    const [qrData, setQrData] = useState<{ secret: string; otpauth: string } | null>(null);
    const [loading, setLoading] = useState(false);
    const [otpCode, setOtpCode] = useState('');
    const [verifyError, setVerifyError] = useState('');

    useEffect(() => {
        if (isOpen && step === 1 && !qrData) {
            setLoading(true);
            fetch('/.netlify/functions/generate-2fa-secret', {
                method: 'POST',
                body: JSON.stringify({ email })
            })
            .then(res => res.json())
            .then(data => {
                setQrData(data);
                setLoading(false);
            })
            .catch(() => {
                setVerifyError("Failed to generate secret");
                setLoading(false);
            });
        }
    }, [isOpen, step, email]);

    const handleVerify = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setVerifyError('');

        try {
            const res = await fetch('/.netlify/functions/finalize-2fa', {
                method: 'POST',
                body: JSON.stringify({ email, secret: qrData?.secret, code: otpCode })
            });
            const data = await res.json();

            if (data.success) {
                onComplete(data.backupCodes);
            } else {
                setVerifyError(data.message || 'Invalid code');
            }
        } catch (err) {
            setVerifyError('Verification failed');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return (
        <ConfirmationModal
            isOpen={isOpen}
            onClose={onClose}
            onConfirm={() => {}} // Controlled manually
            title="Setup 2FA"
            confirmText=""
            cancelText="Close"
        >
            <div className="space-y-6">
                {step === 1 && (
                    <div className="flex flex-col items-center text-center">
                        {loading ? (
                            <SpinnerIcon className="w-12 h-12 text-indigo-500 animate-spin my-8" />
                        ) : qrData ? (
                            <>
                                <p className="text-sm text-slate-600 dark:text-slate-300 mb-4">
                                    Scan this QR code with your authenticator app (Google Authenticator, Authy, etc.).
                                </p>
                                <div className="bg-white p-4 rounded-lg shadow-inner mb-4">
                                    <img 
                                        src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData.otpauth)}`} 
                                        alt="2FA QR Code" 
                                        className="w-48 h-48"
                                    />
                                </div>
                                <p className="text-xs font-mono text-slate-500 bg-slate-100 dark:bg-slate-800 p-2 rounded w-full break-all mb-6">
                                    Secret: {qrData.secret}
                                </p>

                                <form onSubmit={handleVerify} className="w-full">
                                    <input
                                        type="text"
                                        placeholder="Enter 6-digit code"
                                        value={otpCode}
                                        onChange={e => setOtpCode(e.target.value.replace(/[^0-9]/g, '').slice(0, 6))}
                                        className="modern-input text-center text-lg tracking-widest font-mono mb-2"
                                        autoFocus
                                    />
                                    {verifyError && <p className="text-xs text-red-500 mb-2">{verifyError}</p>}
                                    <button 
                                        type="submit" 
                                        disabled={otpCode.length !== 6 || loading}
                                        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2 rounded-lg disabled:opacity-50"
                                    >
                                        {loading ? <SpinnerIcon className="w-4 h-4 animate-spin mx-auto"/> : 'Verify & Enable'}
                                    </button>
                                </form>
                            </>
                        ) : (
                            <p className="text-red-500">Error loading setup data.</p>
                        )}
                    </div>
                )}
            </div>
        </ConfirmationModal>
    );
}

